class CacheManager:
    """Centralized cache management class."""

    def __init__(self, client):
        self.client = client

    def get(self, key):
        """Get a value from cache."""
        try:
            return self.client.get(key)
        except Exception as e:
            app.logger.error(f"Memcached GET error for key '{key}': {e}")
            return None

    def set(self, key, value, ttl=None):
        """Set a value in cache with optional TTL."""
        if ttl is None:
            ttl = app.config['DEFAULT_CACHE_TTL']
        try:
            self.client.set(key, value, expire=ttl)
            return True
        except Exception as e:
            app.logger.error(f"Memcached SET error for key '{key}': {e}")
            return False

    def delete(self, key):
        """Delete a value from cache."""
        try:
            self.client.delete(key)
            return True
        except Exception as e:
            app.logger.error(f"Memcached DELETE error for key '{key}': {e}")
            return False

    def flush_all(self):
        """Flush all cache entries."""
        try:
            self.client.flush_all()
            return True
        except Exception as e:
            app.logger.error(f"Memcached FLUSH_ALL error: {e}")
            return False

    def get_multi(self, keys):
        """Get multiple values from cache."""
        try:
            return self.client.get_many(keys)
        except Exception as e:
            app.logger.error(f"Memcached GET_MULTI error: {e}")
            return {}

    def set_multi(self, mapping, ttl=None):
        """Set multiple values in cache."""
        if ttl is None:
            ttl = app.config['DEFAULT_CACHE_TTL']
        try:
            self.client.set_many(mapping, expire=ttl)
            return True
        except Exception as e:
            app.logger.error(f"Memcached SET_MULTI error: {e}")
            return False

    def increment(self, key, value=1):
        """Increment a counter in cache."""
        try:
            return self.client.incr(key, value)
        except Exception as e:
            app.logger.error(f"Memcached INCR error for key '{key}': {e}")
            return None

    def decrement(self, key, value=1):
        """Decrement a counter in cache."""
        try:
            return self.client.decr(key, value)
        except Exception as e:
            app.logger.error(f"Memcached DECR error for key '{key}': {e}")
            return None


