def generate_cache_key(*args, **kwargs):
    """Generate a consistent cache key from arguments."""
    key_data = json.dumps({'args': args, 'kwargs': kwargs}, sort_keys=True, default=str)
    return hashlib.md5(key_data.encode()).hexdigest()


def cache_response(ttl=None, key_prefix='api'):
    """Decorator to cache API responses."""
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            # Build cache key from request
            cache_key = f"{key_prefix}:{f.__name__}:{generate_cache_key(request.path, str(request.args))}"

            # Try to get from cache
            cached = cache_manager.get(cache_key)
            if cached is not None:
                response = cached
                response['_cache'] = 'HIT'
                return jsonify(response)

            # Execute the function
            result = f(*args, **kwargs)

            # Cache the result
            effective_ttl = ttl or app.config['API_CACHE_TTL']
            if isinstance(result, dict):
                cache_manager.set(cache_key, result, ttl=effective_ttl)
                result['_cache'] = 'MISS'
                return jsonify(result)

            return result
        return decorated_function
    return decorator


def cache_db_query(ttl=None, key_prefix='db'):
    """Decorator to cache database query results."""
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            cache_key = f"{key_prefix}:{f.__name__}:{generate_cache_key(*args, **kwargs)}"

            # Try to get from cache
            cached = cache_manager.get(cache_key)
            if cached is not None:
                return cached

            # Execute the query function
            result = f(*args, **kwargs)

            # Cache the result
            effective_ttl = ttl or app.config['DB_CACHE_TTL']
            if result is not None:
                cache_manager.set(cache_key, result, ttl=effective_ttl)

            return result
        return decorated_function
    return decorator


