# Rate limiting using Memcached
def rate_limit(max_requests=100, window=60):
    """Rate limiting decorator using Memcached."""
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            client_ip = request.remote_addr
            rate_key = f"rate_limit:{client_ip}:{f.__name__}"

            current = cache_manager.get(rate_key)
            if current is None:
                cache_manager.set(rate_key, 1, ttl=window)
            elif isinstance(current, int) and current >= max_requests:
                return jsonify({
                    'error': 'Rate limit exceeded',
                    'max_requests': max_requests,
                    'window_seconds': window
                }), 429
            else:
                try:
                    cache_manager.increment(rate_key)
                except Exception:
                    pass

            return f(*args, **kwargs)
        return decorated_function
    return decorator


# Request timing middleware
@app.before_request
def before_request():
    g.start_time = time.time()


@app.after_request
def after_request(response):
    if hasattr(g, 'start_time'):
        elapsed = time.time() - g.start_time
        response.headers['X-Response-Time'] = f"{elapsed:.4f}s"
    return response


