# Batch endpoint for fetching multiple resources
@app.route('/api/batch/users', methods=['POST'])
@rate_limit(max_requests=50, window=60)
def batch_get_users():
    """Batch fetch multiple users by IDs."""
    data = request.get_json()
    if not data or 'ids' not in data:
        return jsonify({'error': 'Missing "ids" in request body'}), 400

    user_ids = data['ids']
    if len(user_ids) > 50:
        return jsonify({'error': 'Maximum 50 IDs per batch request'}), 400

    users = []
    for uid in user_ids:
        user = db_get_user(str(uid))
        if user:
            users.append(user)

    return jsonify({
        'data': users,
        'requested': len(user_ids),
        'found': len(users),
        'timestamp': time.time()
    })


